def main():
    cwd = os.getcwd()
    print(f"Writing 101 files into: {cwd}")
    for rel, enc in FILES.items():
        path = os.path.join(cwd, rel.replace("/", os.sep))
        os.makedirs(os.path.dirname(path), exist_ok=True)
        data = base64.b64decode(enc)
        with open(path, "wb") as f:
            f.write(data)
        print(f"  wrote {rel}")
    print(f"\nDone! {len(FILES)} files written.")
    print("\nNext steps:")
    print("  git add .")
    print("  git commit -m \"chore: initial commit IOS+ v1.0.0\"")
    print("  git push -u origin main")

if __name__ == "__main__":
    main()